def calculate_major_titles(grand_slam_victories):
    majors = ['Australian Open', 'French Open', 'Wimbledon', 'US Open']
    major_titles = {major: grand_slam_victories.count(major) for major in majors}
    return major_titles

# Example usage:
victories = ['French Open', 'Australian Open', 'French Open', 'US Open', 'French Open']
print(calculate_major_titles(victories))
# Output: {'Australian Open': 1, 'French Open': 3, 'Wimbledon': 0, 'US Open': 1}
